## 实用示例

### 示例1：自动化登录流程
```javascript
async function automatedLogin(url, username, password) {
  // 1. 打开登录页面
  const tab = await browser({
    action: "open",
    profile: "openclaw",
    targetUrl: url
  })

  try {
    // 2. 等待页面加载
    await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "wait",
        timeMs: 5000
      }
    })

    // 3. 填写登录信息
    await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "fill",
        fields: [
          { selector: "input[name='username']", value: username },
          { selector: "input[name='password']", value: password }
        ]
      }
    })

    // 4. 点击登录按钮
    await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "click",
        selector: "button[type='submit']"
      }
    })

    // 5. 等待登录完成
    await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "wait",
        timeMs: 3000
      }
    })

    // 6. 验证登录成功
    const snapshot = await browser({
      action: "snapshot",
      targetId: tab.targetId
    })

    // 检查是否包含登录成功标识
    const success = checkLoginSuccess(snapshot)

    // 7. 返回结果
    return {
      success: success,
      screenshot: await browser({
        action: "screenshot",
        targetId: tab.targetId
      })
    }

  } finally {
    // 8. 关闭标签页
    await browser({
      action: "close",
      targetId: tab.targetId
    })
  }
}
```

