### 示例3：网页监控
```javascript
class WebsiteMonitor {
  constructor(url, checkInterval = 300000) { // 5分钟
    this.url = url
    this.checkInterval = checkInterval
    this.lastStatus = null
    this.isMonitoring = false
  }

  async check() {
    const tab = await browser({
      action: "open",
      profile: "openclaw",
      targetUrl: this.url
    })

    try {
      const startTime = Date.now()

      // 检查页面加载时间
      await browser({
        action: "act",
        targetId: tab.targetId,
        request: {
          kind: "wait",
          timeMs: 30000  // 30秒超时
        }
      })

      const loadTime = Date.now() - startTime

      // 检查关键元素
      const snapshot = await browser({
        action: "snapshot",
        targetId: tab.targetId
      })

      // 检查HTTP状态（通过JavaScript）
      const status = await browser({
        action: "act",
        targetId: tab.targetId,
        request: {
          kind: "evaluate",
          fn: "() => window.performance.getEntriesByType('navigation')[0].responseStatus"
        }
      })

      // 截图用于记录
      const screenshot = await browser({
        action: "screenshot",
        targetId: tab.targetId
      })

      return {
        timestamp: new Date().toISOString(),
        url: this.url,
        status: status || 200,
        loadTime: loadTime,
        hasContent: checkContentExists(snapshot),
        screenshot: screenshot
      }

    } finally {
      await browser({
        action: "close",
        targetId: tab.targetId
      })
    }
  }

  start() {
    this.isMonitoring = true
    this.monitorLoop()
  }

  stop() {
    this.isMonitoring = false
  }

  async monitorLoop() {
    while (this.isMonitoring) {
      try {
        const status = await this.check()
        this.lastStatus = status

        // 发送通知或保存到数据库
        await this.handleStatusChange(status)

      } catch (error) {
        console.error('监控检查失败:', error)

        // 记录错误状态
        this.lastStatus = {
          timestamp: new Date().toISOString(),
          url: this.url,
          error: error.message,
          status: 'error'
        }
      }

      // 等待下一次检查
      await new Promise(resolve => {
        setTimeout(resolve, this.checkInterval)
      })
    }
  }

  async handleStatusChange(status) {
    // 实现状态变化处理逻辑
    if (status.loadTime > 5000) {
      console.warn(`页面加载缓慢: ${status.loadTime}ms`)
    }

    if (!status.hasContent) {
      console.error('页面内容缺失')
    }
  }
}
```

