### 错误恢复策略
```javascript
class ResilientBrowser {
  constructor() {
    this.tab = null
  }

  async open(url) {
    try {
      this.tab = await browser({
        action: "open",
        profile: "openclaw",
        targetUrl: url
      })
      return this.tab
    } catch (error) {
      // 尝试重启浏览器
      await this.restartBrowser()
      return this.open(url)
    }
  }

  async restartBrowser() {
    // 停止浏览器
    await browser({ action: "stop" })
    // 等待
    await new Promise(resolve => setTimeout(resolve, 2000))
    // 启动浏览器
    await browser({ action: "start" })
  }

  async execute(action) {
    try {
      return await browser({
        ...action,
        targetId: this.tab?.targetId
      })
    } catch (error) {
      if (error.message.includes("target closed") || 
          error.message.includes("no such target")) {
        // 标签页已关闭，重新打开
        await this.open(this.lastUrl)
        return this.execute(action)
      }
      throw error
    }
  }
}
