### 2. 并行处理优化
```javascript
// 控制并发数量
class ParallelBrowser {
  constructor(maxConcurrent = 3) {
    this.maxConcurrent = maxConcurrent
    this.queue = []
    this.active = 0
  }

  async execute(task) {
    return new Promise((resolve, reject) => {
      this.queue.push({ task, resolve, reject })
      this.processQueue()
    })
  }

  async processQueue() {
    if (this.active >= this.maxConcurrent || this.queue.length === 0) {
      return
    }

    this.active++
    const { task, resolve, reject } = this.queue.shift()

    try {
      const result = await task()
      resolve(result)
    } catch (error) {
      reject(error)
    } finally {
      this.active--
      this.processQueue()
    }
  }
}

// 使用示例
const parallel = new ParallelBrowser(3)
const urls = ["url1", "url2", "url3", "url4", "url5"]

const results = await Promise.all(
  urls.map(url => 
    parallel.execute(() => 
      browser({
        action: "open",
        profile: "openclaw",
        targetUrl: url
      }).then(tab => {
        // 执行操作...
        return browser({ action: "close", targetId: tab.targetId })
      })
    )
  )
)
