### 3. 缓存策略
```javascript
// 实现页面缓存
class BrowserCache {
  constructor(ttl = 3600000) { // 1小时
    this.cache = new Map()
    this.ttl = ttl
  }

  async get(url, forceRefresh = false) {
    const cached = this.cache.get(url)

    if (!forceRefresh && cached && Date.now() - cached.timestamp < this.ttl) {
      return cached.data
    }

    // 获取新数据
    const data = await this.fetch(url)
    this.cache.set(url, {
      data: data,
      timestamp: Date.now()
    })

    return data
  }

  async fetch(url) {
    const tab = await browser({
      action: "open",
      profile: "openclaw",
      targetUrl: url
    })

    try {
      const snapshot = await browser({
        action: "snapshot",
        targetId: tab.targetId
      })

      return {
        snapshot: snapshot,
        timestamp: new Date().toISOString()
      }
    } finally {
      await browser({
        action: "close",
        targetId: tab.targetId
      })
    }
  }

  clear() {
    this.cache.clear()
  }

  invalidate(url) {
    this.cache.delete(url)
  }
}
