## 安全注意事项

### 1. 输入验证
```javascript
function validateUrl(url) {
  try {
    const parsed = new URL(url)

    // 只允许HTTP/HTTPS
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      throw new Error('只支持HTTP/HTTPS协议')
    }

    // 检查域名（可选）
    const allowedDomains = ['example.com', 'trusted-site.org']
    if (!allowedDomains.includes(parsed.hostname)) {
      console.warn(`访问非信任域名: ${parsed.hostname}`)
    }

    return true
  } catch (error) {
    throw new Error(`无效的URL: ${error.message}`)
  }
}

// 使用前验证
validateUrl(userInput)
```

