async function safeEvaluate(tabId, code) {
  // 验证代码
  if (code.includes('eval(') || code.includes('Function(')) {
    throw new Error('不允许使用eval或Function')
  }

  return await browser({
    action: "act",
    targetId: tabId,
    request: {
      kind: "evaluate",
      fn: `(function() {
        ${code}
      })()`
    }
  })
}
