// 批量下载图片
async function downloadImages(url, selector, outputDir) {
  const tab = await browser({
    action: "open",
    profile: "openclaw",
    targetUrl: url
  })

  try {
    // 获取所有图片URL
    const imageUrls = await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "evaluate",
        fn: `
          (selector) => {
            const images = document.querySelectorAll(selector)
            return Array.from(images).map(img => img.src)
          }
        `,
        args: [selector]
      }
    })

    // 下载每个图片
    for (let i = 0; i < imageUrls.length; i++) {
      const imageUrl = imageUrls[i]

      // 在新标签页中打开图片
      const imageTab = await browser({
        action: "open",
        profile: "openclaw",
        targetUrl: imageUrl
      })

      try {
        // 截图保存
        const screenshot = await browser({
          action: "screenshot",
          targetId: imageTab.targetId
        })

        // 保存到文件
        await write({
          path: `${outputDir}/image-${i}.png`,
          content: screenshot,
          encoding: 'base64'
        })

        console.log(`已保存: image-${i}.png`)
      } finally {
        await browser({
          action: "close",
          targetId: imageTab.targetId
        })
      }

      // 避免请求过快
      await new Promise(resolve => setTimeout(resolve, 500))
    }

    return {
      downloaded: imageUrls.length,
      outputDir: outputDir
    }
  } finally {
    await browser({
      action: "close",
      targetId: tab.targetId
    })
  }
}
