// Headless Browser 基础测试示例
// 这个示例展示了如何使用无头浏览器进行基本操作

async function basicBrowserTest() {
  console.log("=== Headless Browser 基础测试 ===\n")

  try {
    // 1. 检查浏览器状态
    console.log("1. 检查浏览器状态...")
    const status = await browser({ action: "status" })
    console.log("浏览器状态:", status.status)

    // 2. 打开测试网页
    console.log("\n2. 打开测试网页...")
    const tab = await browser({
      action: "open",
      profile: "openclaw",
      targetUrl: "https://httpbin.org/html"
    })
    console.log("标签页ID:", tab.targetId)

    // 3. 等待页面加载
    console.log("\n3. 等待页面加载...")
    await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "wait",
        timeMs: 3000
      }
    })

    // 4. 获取页面标题
    console.log("\n4. 获取页面标题...")
    const title = await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "evaluate",
        fn: "() => document.title"
      }
    })
    console.log("页面标题:", title)

    // 5. 截图
    console.log("\n5. 截图...")
    const screenshot = await browser({
      action: "screenshot",
      targetId: tab.targetId,
      fullPage: false
    })
    console.log("截图完成，大小:", screenshot?.length || 0, "bytes")

    // 6. 获取页面快照
    console.log("\n6. 获取页面快照...")
    const snapshot = await browser({
      action: "snapshot",
      targetId: tab.targetId,
      refs: "aria",
      compact: true
    })
    console.log("快照包含元素数量:", snapshot?.elements?.length || 0)

    // 7. 提取页面内容
    console.log("\n7. 提取页面内容...")
    const content = await browser({
      action: "act",
      targetId: tab.targetId,
      request: {
        kind: "evaluate",
        fn: `
          () => {
            // 获取所有段落文本
            const paragraphs = Array.from(document.querySelectorAll('p'))
            return paragraphs.map(p => p.textContent).filter(text => text.trim().length > 0)
          }
        `
      }
    })
    console.log("找到段落:", content.length)
    if (content.length > 0) {
      console.log("第一个段落:", content[0].substring(0, 100) + "...")
    }

    // 8. 关闭标签页
    console.log("\n8. 关闭标签页...")
    await browser({
      action: "close",
      targetId: tab.targetId
    })
    console.log("标签页已关闭")

    console.log("\n=== 测试完成 ===")
    return {
      success: true,
      title: title,
      screenshotSize: screenshot?.length || 0,
      paragraphs: content.length
    }

  } catch (error) {
    console.error("测试失败:", error.message)
    console.error("错误堆栈:", error.stack)
    return {
      success: false,
      error: error.message
    }
  }
}

