// 登录自动化示例
// 演示如何使用无头浏览器自动化登录流程

class LoginAutomation {
  constructor() {
    this.tab = null
    this.config = {
      timeout: 10000, // 10秒超时
      retryCount: 2   // 重试次数
    }
  }

  // 打开登录页面
  async openLoginPage(url) {
    console.log(`打开登录页面: ${url}`)

    this.tab = await browser({
      action: "open",
      profile: "openclaw",
      targetUrl: url
    })

    // 等待页面加载
    await this.waitForPageLoad()

    console.log("登录页面已打开")
    return this.tab
  }

  // 等待页面加载
  async waitForPageLoad() {
    return await browser({
      action: "act",
      targetId: this.tab.targetId,
      request: {
        kind: "wait",
        timeMs: this.config.timeout
      }
    })
  }

  // 查找元素（支持多种选择器）
  async findElement(selectors) {
    const snapshot = await browser({
      action: "snapshot",
      targetId: this.tab.targetId,
      refs: "aria"
    })

    // 这里简化处理，实际需要解析snapshot
    // 返回第一个找到的元素的引用
    for (const selector of selectors) {
      try {
        // 尝试通过JavaScript查找元素
        const element = await browser({
          action: "act",
          targetId: this.tab.targetId,
          request: {
            kind: "evaluate",
            fn: `
              (selector) => {
                const el = document.querySelector(selector)
                return el ? {
                  tagName: el.tagName,
                  type: el.type,
                  name: el.name,
                  id: el.id,
                  className: el.className,
                  placeholder: el.placeholder
                } : null
              }
            `,
            args: [selector]
          }
        })

        if (element) {
          console.log(`找到元素: ${selector}`, element)
          return { selector, element }
        }
      } catch (error) {
        // 继续尝试下一个选择器
      }
    }

    throw new Error(`未找到元素: ${selectors.join(', ')}`)
  }

  // 填写表单
  async fillForm(fields) {
    console.log("填写表单...")

    for (const field of fields) {
      const { selector, element } = await this.findElement(field.selectors)

      console.log(`填写 ${field.name}: ${field.value.substring(0, 10)}...`)

      // 点击元素聚焦
      await browser({
        action: "act",
        targetId: this.tab.targetId,
        request: {
          kind: "click",
          selector: selector
        }
      })

      // 清空现有内容（如果有）
      await browser({
        action: "act",
        targetId: this.tab.targetId,
        request: {
          kind: "evaluate",
          fn: `
            (selector) => {
              const el = document.querySelector(selector)
              if (el) el.value = ''
            }
          `,
          args: [selector]
        }
      })

      // 输入文本
      await browser({
        action: "act",
        targetId: this.tab.targetId,
        request: {
          kind: "type",
          selector: selector,
          text: field.value,
          slowly: true // 模拟真人输入
        }
      })

      // 短暂等待
      await new Promise(resolve => setTimeout(resolve, 200))
    }

    console.log("表单填写完成")
  }

  // 点击登录按钮
  async clickLoginButton(selectors) {
    console.log("点击登录按钮...")

    const { selector } = await this.findElement(selectors)

    await browser({
      action: "act",
      targetId: this.tab.targetId,
      request: {
        kind: "click",
        selector: selector
      }
    })

    console.log("登录按钮已点击")

    // 等待登录处理
    await new Promise(resolve => setTimeout(resolve, 2000))
  }

  // 检查登录是否成功
  async checkLoginSuccess(successIndicators) {
    console.log("检查登录结果...")

    try {
      // 获取当前URL
      const currentUrl = await browser({
        action: "act",
        targetId: this.tab.targetId,
        request: {
          kind: "evaluate",
          fn: "() => window.location.href"
        }
      })

      console.log("当前URL:", currentUrl)

      // 检查页面内容
      const pageContent = await browser({
        action: "act",
        targetId: this.tab.targetId,
        request: {
          kind: "evaluate",
          fn: `
            () => {
              return {
                title: document.title,
                hasWelcomeText: document.body.innerText.includes('Welcome') || 
                               document.body.innerText.includes('欢迎') ||
                               document.body.innerText.includes('Dashboard'),
                hasErrorText: document.body.innerText.includes('Error') || 
                             document.body.innerText.includes('错误') ||
                             document.body.innerText.includes('Invalid')
              }
            }
          `
        }
      })

      console.log("页面分析:", pageContent)

      // 截图记录
      const screenshot = await browser({
        action: "screenshot",
        targetId: this.tab.targetId
      })

      // 判断登录结果
      const success = !pageContent.hasErrorText && 
                     (pageContent.hasWelcomeText || 
                      !currentUrl.includes('login') ||
                      successIndicators.some(indicator => 
                        pageContent.title.includes(indicator) || 
                        currentUrl.includes(indicator)
                      ))

      return {
        success: success,
        url: currentUrl,
        title: pageContent.title,
        screenshot: screenshot,
        details: pageContent
      }

    } catch (error) {
      console.error("检查登录状态时出错:", error)
      return {
        success: false,
        error: error.message
      }
    }
  }

  // 执行登录
  async login(options) {
    const { url, username, password, usernameSelectors, passwordSelectors, buttonSelectors, successIndicators } = options

    console.log(`\n=== 开始登录自动化 ===`)
    console.log(`目标: ${url}`)
    console.log(`用户: ${username}`)

    try {
      // 1. 打开登录页面
      await this.openLoginPage(url)

      // 2. 填写登录表单
      await this.fillForm([
        {
          name: "用户名",
          value: username,
          selectors: usernameSelectors || [
            "input[name='username']",
            "input[name='email']",
            "input[type='text']",
            "#username",
            "#email"
          ]
        },
        {
          name: "密码", 
          value: password,
          selectors: passwordSelectors || [
            "input[name='password']",
            "input[type='password']",
            "#password"
          ]
        }
      ])

      // 3. 点击登录按钮
      await this.clickLoginButton(
        buttonSelectors || [
          "button[type='submit']",
          "input[type='submit']",
          "button:contains('Login')",
          "button:contains('登录')",
          ".login-btn",
          "#login-button"
        ]
      )

      // 4. 检查登录结果
      const result = await this.checkLoginSuccess(
        successIndicators || ["dashboard", "welcome", "home", "main"]
      )

      console.log(`\n登录结果: ${result.success ? '成功' : '失败'}`)

      return result

    } catch (error) {
      console.error(`登录过程出错: ${error.message}`)

      // 尝试截图记录错误状态
      try {
        if (this.tab) {
          const errorScreenshot = await browser({
            action: "screenshot",
            targetId: this.tab.targetId
          })
          return {
            success: false,
            error: error.message,
            screenshot: errorScreenshot
          }
        }
      } catch (screenshotError) {
        // 忽略截图错误
      }

      return {
        success: false,
        error: error.message
      }

    } finally {
      // 5. 清理资源
      await this.cleanup()
    }
  }

  // 清理资源
  async cleanup() {
    if (this.tab) {
      try {
        await browser({
          action: "close",
          targetId: this.tab.targetId
        })
        console.log("资源已清理")
      } catch (error) {
        console.warn("关闭标签页时出错:", error.message)
      }
      this.tab = null
    }
  }
}

